def register_agent_catalog_routes(api_router, db, get_current_user):

    @api_router.get("/catalog/templates")
    async def list_templates(category: Optional[str] = None):
        """Browse builtin agent templates."""
        templates = BUILTIN_TEMPLATES
        if category:
            templates = [t for t in templates if t.get("category") == category]
        return {"templates": templates, "total": len(templates)}

    @api_router.get("/catalog/templates/{template_id}")
    async def get_template(template_id: str):
        """Get a specific template."""
        tpl = next((t for t in BUILTIN_TEMPLATES if t["template_id"] == template_id), None)
        if not tpl:
            raise HTTPException(404, "Template not found")
        return tpl

    @api_router.post("/catalog/marketplace/{agent_id}/clone")
    async def clone_marketplace_agent(agent_id: str, request: Request):
        """Clone a marketplace agent into a workspace."""
        user = await get_current_user(request)
        ws_id = request.query_params.get("workspace_id")
        if not ws_id:
            raise HTTPException(400, "workspace_id required")
        source = await db.agent_marketplace.find_one({"agent_id": agent_id, "status": "published"}, {"_id": 0})
        if not source:
            raise HTTPException(404, "Marketplace agent not found")
        new_id = f"nxa_{uuid.uuid4().hex[:12]}"
        now = datetime.now(timezone.utc).isoformat()
        agent = {
            "agent_id": new_id, "workspace_id": ws_id, "created_by": user["user_id"],
            "name": source["name"], "description": source.get("description", ""),
            "base_model": source.get("base_model", "claude"), "system_prompt": source.get("system_prompt", ""),
            "color": source.get("color", "#6366f1"), "avatar": source["name"][:2].upper(),
            "version": 1, "version_history": [], "status": "active", "visibility": "workspace",
            "category": source.get("category", "custom"), "tags": source.get("tags") or [],
            "personality": source.get("personality") or {}, "skills": source.get("skills") or [],
            "allowed_tools": [], "denied_tools": [], "guardrails": source.get("guardrails") or {},
            "preferred_role": "contributor",
            "evaluation": {"last_assessed": None, "overall_score": 0, "skill_scores": {}, "badges": []},
            "stats": {"total_messages": 0, "total_tool_calls": 0, "avg_confidence": 0, "avg_response_time_ms": 0, "total_cost_usd": 0, "channels_active_in": 0, "last_active": None},
            "training": {"enabled": False, "total_chunks": 0, "total_sources": 0, "total_sessions": 0},
            "forked_from": agent_id, "fork_count": 0, "created_at": now, "updated_at": now,
        }
        await db.nexus_agents.insert_one(agent)
        await db.agent_marketplace.update_one({"agent_id": agent_id}, {"$inc": {"installs": 1}})
        agent.pop("_id", None)
        return agent

    @api_router.post("/workspaces/{ws_id}/agents/{agent_id}/rate")
    async def rate_workspace_agent(ws_id: str, agent_id: str, request: Request):
        """Rate a workspace agent (1-5 stars)."""
        user = await get_current_user(request)
        body = await request.json()
        rating = body.get("rating", 0)
        if not 1 <= rating <= 5:
            raise HTTPException(400, "Rating must be 1-5")
        now = datetime.now(timezone.utc).isoformat()
        await db.agent_ratings.update_one(
            {"agent_id": agent_id, "user_id": user["user_id"]},
            {"$set": {"rating": rating, "review": body.get("review", ""), "updated_at": now}},
            upsert=True
        )
        return {"status": "rated"}
